// WOA 悬浮注入 — 在 WPS协作 DevTools 控制台粘贴运行
// 再次运行可关闭
(function(){var id='cc-float-frame';var f=document.getElementById(id);if(f){f.remove();return;}var docUrl='';var docTitle=document.title||'';var wvs=[...document.querySelectorAll('webview')];for(var i=wvs.length-1;i>=0;i--){var s=wvs[i].src||'';var m=s.match(/365\.kdocs\.cn\/l\/[A-Za-z0-9]+/);if(m){docUrl=s.split('?')[0];break;}}if(!docUrl){var links=document.body.innerHTML.match(/https:\/\/365\.kdocs\.cn\/l\/[A-Za-z0-9]+/g);if(links)docUrl=links[links.length-1];}f=document.createElement('iframe');f.id=id;f.src='http://localhost:5174/panel?mode=float&docUrl='+encodeURIComponent(docUrl)+'&docTitle='+encodeURIComponent(docTitle);f.allow='clipboard-write';f.style.cssText='position:fixed;right:0;bottom:0;width:480px;height:640px;border:none;z-index:99999;background:transparent;';f.setAttribute('allowtransparency','true');document.body.appendChild(f);})();
